// src/services/api.js
import axios from "axios";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:8080/api";

// Create axios instance
const api = axios.create({
  baseURL: API_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

// 🚗 Vehicles
api.getVehicles = async () => {
  const response = await api.get("/vehicles");
  return response.data;
};

api.addVehicle = async (vehicle) => {
  const response = await api.post("/vehicles", vehicle);
  return response.data;
};

// 🗺️ Routes
api.optimizeRoute = async (routeRequest) => {
  const response = await api.post("/routes/optimize", routeRequest);
  return response.data;
};

// 📍 Geocoding
api.geocode = async (address) => {
  const response = await api.get(`/geocode?address=${encodeURIComponent(address)}`);
  return response.data;
};

// 🚨 Alerts
api.getAlerts = async () => {
  const response = await api.get("/alerts");
  return response.data;
};

export default api;
